using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Build a repeatable input: ~10,000 words of varying length
var rng = new Random(42);
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
string text = string.Join(' ', words);
var analyzer = new TextAnalyzer(text);

const int WarmupIterations = 500;
const int MeasuredIterations = 5000;

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount:N0}");
Console.WriteLine($"Warmup: {WarmupIterations}  Measured: {MeasuredIterations}");
Console.WriteLine();

Bench("AverageWordLength",  () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Bench("UniqueWordCount",    () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void Bench(string name, Func<object?> action)
{
    // warmup
    for (int i = 0; i < WarmupIterations; i++) action();

    // collect per-iteration timings
    var timings = new double[MeasuredIterations];
    for (int i = 0; i < MeasuredIterations; i++)
    {
        var sw = Stopwatch.StartNew();
        action();
        sw.Stop();
        timings[i] = sw.Elapsed.TotalNanoseconds;
    }

    Array.Sort(timings);
    double median = timings[MeasuredIterations / 2];
    double mean   = timings.Average();
    double p5     = timings[(int)(MeasuredIterations * 0.05)];
    double p95    = timings[(int)(MeasuredIterations * 0.95)];

    Console.WriteLine($"{name,-25} | Mean: {FormatNs(mean),12} | Median: {FormatNs(median),12} | P5: {FormatNs(p5),12} | P95: {FormatNs(p95),12}");
}

static string FormatNs(double ns)
{
    if (ns < 1_000) return $"{ns:F1} ns";
    if (ns < 1_000_000) return $"{ns / 1_000:F2} μs";
    return $"{ns / 1_000_000:F2} ms";
}

